def dec_axis(bs,scale=1):
 v=256-bs[-1]; out=[v]
 for d in reversed(bs[:-1]): v-=d; out.append(v)
 out.reverse(); return [x*scale for x in out]
def parse(b,off):
 xp=b[off]; nx=b[off+1]; xa=b[off+2:off+2+nx]; pos=off+2+nx
