  yp=b[pos]; ny=b[pos+1]; ya=b[pos+2:pos+2+ny]; do=pos+2+ny; return (xp,nx,dec_axis(xa,40 if xp==0x3e else 1),yp,ny,dec_axis(ya,40 if yp==0x3e else 1),do,list(b[do:do+nx*ny]))
 do=pos; return (xp,nx,dec_axis(xa,40 if xp==0x3e else 1),None,None,None,do,list(b[do:do+nx]))
def cvdelta(d,k): return d/128 if k=='fuel' else d*360/(129*4)
